using System.Globalization;
using Avalonia.Data.Converters;
using Avalonia.Media.Imaging;

namespace VisualRelay.App.Views.Controls;

/// <summary>
/// Converts a filesystem path string to a <see cref="Bitmap"/> when the
/// path points to a file with a recognised image extension; returns null
/// for non-image files, missing files, or null/empty paths.
/// </summary>
public class ImagePathToBitmapConverter : IValueConverter
{
    public static readonly ImagePathToBitmapConverter Instance = new();

    private static readonly HashSet<string> ImageExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".png", ".jpg", ".jpeg", ".gif", ".bmp", ".webp"
    };

    public object? Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is not string path || path.Length == 0)
            return null;

        var ext = Path.GetExtension(path);
        if (string.IsNullOrEmpty(ext) || !ImageExtensions.Contains(ext))
            return null;

        if (!File.Exists(path))
            return null;

        try
        {
            return new Bitmap(path);
        }
        catch
        {
            return null;
        }
    }

    public object? ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        return value;
    }
}

using System.Globalization;
using Avalonia.Data.Converters;

namespace VisualRelay.App.Views.Controls;

/// <summary>
/// Returns <c>true</c> when the value is a path whose file extension is a
/// recognised image type (.png, .jpg, .jpeg, .gif, .bmp, .webp).
/// Used to control <c>IsVisible</c> on the inline image preview so that
/// non-image attachments do not render an empty Image element.
/// </summary>
public class IsImageExtensionConverter : IValueConverter
{
    public static readonly IsImageExtensionConverter Instance = new();

    private static readonly HashSet<string> ImageExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".png", ".jpg", ".jpeg", ".gif", ".bmp", ".webp"
    };

    public object? Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is not string path || path.Length == 0)
            return false;

        var ext = Path.GetExtension(path);
        return !string.IsNullOrEmpty(ext) && ImageExtensions.Contains(ext);
    }

    public object? ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        return value;
    }
}

using System.Globalization;
using Avalonia.Data.Converters;

namespace VisualRelay.App.Views.Controls;

/// <summary>
/// Multiplies a double value by a fraction passed as the converter
/// parameter.  When the parameter is omitted or not parseable the
/// default is <c>0.75</c>.
///
/// Used to bind <c>Image.MaxWidth</c> to
/// <c>ScrollViewer.Viewport.Width * 0.75</c> so inline image previews
/// consume 50–75 % of the available panel width.
/// </summary>
public class FractionConverter : IValueConverter
{
    public static readonly FractionConverter Instance = new();

    public object? Convert(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        if (value is not double d)
            return null;

        var factor = 0.75;
        if (parameter is string s && double.TryParse(s, NumberStyles.Float, CultureInfo.InvariantCulture, out var parsed))
            factor = parsed;

        return d * factor;
    }

    public object? ConvertBack(object? value, Type targetType, object? parameter, CultureInfo culture)
    {
        return value;
    }
}

